  1→// User input processing and drag-to-swap mechanics
  2→
  3→import {
  4→    getTileValue,
  5→    createTile,
  6→    createJokerTile,
  7→    isBlocked,
  8→    isBlockedWithLife,
  9→    isBlockedMovable,
 10→    isBlockedWithMergeCount,
 11→    isJoker,
 12→    isTileFreeSwapTile,
 13→    isTileStickyFreeSwapTile,
 14→    isTileFreeSwapHorizontalTile,
 15→    isTileFreeSwapVerticalTile,
 16→    isTileHammerTile,
 17→    isTileHalverTile,
 18→    isTileTeleportTile,
 19→    isWildTeleportTile,
 20→    getDisplayValue,
 21→    findBestJokerValue,
 22→    getUniqueTileValues,
 23→} from "./tile-helpers.js";
 24→import { track } from "./tracker.js";
 25→import { getMatchTilesForSwap } from "./hint-system.js";
 26→import {
 27→    isTutorialActive,
 28→    isValidTutorialSwap,
 29→    advanceTutorialStep,
 30→    canDragTileInTutorial,
 31→    isTutorialTapStep,
 32→    isValidTutorialTap,
 33→    isTutorialPowerUpStep,
 34→    isValidTutorialPowerUp,
 35→    isValidTutorialPowerUpTarget,
 36→    updateTutorialUI,
 37→} from "./tutorial.js";
 38→
 39→export function setupEventListeners(game) {
 40→    const gameBoard = document.getElementById("gameBoard");
 41→
 42→    // Touch events for mobile
 43→    gameBoard.addEventListener("touchstart", handleTouchStart.bind(game), { passive: false });
 44→    gameBoard.addEventListener("touchmove", handleTouchMove.bind(game), { passive: false });
 45→    gameBoard.addEventListener("touchend", handleTouchEnd.bind(game), { passive: false });
 46→
 47→    // Mouse events for desktop
 48→    gameBoard.addEventListener("mousedown", handleMouseDown.bind(game));
 49→    gameBoard.addEventListener("mousemove", handleMouseMove.bind(game));
 50→    gameBoard.addEventListener("mouseup", handleMouseUp.bind(game));
 51→    gameBoard.addEventListener("mouseleave", handleMouseUp.bind(game));
 52→}
 53→
 54→function handleTouchStart(e) {
 55→    e.preventDefault();
 56→    const touch = e.touches[0];
 57→    startDrag(this, touch.clientX, touch.clientY);
 58→}
 59→
 60→function handleTouchMove(e) {
 61→    e.preventDefault();
 62→    const touch = e.touches[0];
 63→    updateDrag(this, touch.clientX, touch.clientY);
 64→}
 65→
 66→function handleTouchEnd(e) {
 67→    e.preventDefault();
 68→    endDrag(this);
 69→}
 70→
 71→function handleMouseDown(e) {
 72→    startDrag(this, e.clientX, e.clientY);
 73→}
 74→
 75→function handleMouseMove(e) {
 76→    updateDrag(this, e.clientX, e.clientY);
 77→}
 78→
 79→function handleMouseUp() {
 80→    endDrag(this);
 81→}
 82→
 83→
 84→function startDrag(game, x, y) {
 85→    if (!game.gameActive) return;
 86→
 87→    // Clear hint on user interaction (don't start timer until drag ends)
 88→    game.clearHint();
 89→    game.clearHintTimer();
 90→
 91→    const element = document.elementFromPoint(x, y);
 92→    if (element && element.classList.contains("gem")) {
 93→        const row = parseInt(element.dataset.row);
 94→        const col = parseInt(element.dataset.col);
 95→        const tile = game.board[row][col];
 96→
 97→        // Block dragging tiles during tutorial if not part of the tutorial step
 98→        if (isTutorialActive(game) && !canDragTileInTutorial(game, row, col)) {
 99→            return;
100→        }
101→
102→        // Handle power-ups (but not during animations)
103→        if (game.activePowerUp) {
104→            // Prevent power-up usage during animations
105→            if (game.animating) return;
106→
107→            // Check tutorial validation for power-up usage
108→            if (isTutorialActive(game) && isTutorialPowerUpStep(game)) {
109→                // Only allow clicking on the specified tutorial target
110→                if (!isValidTutorialPowerUpTarget(game, row, col)) {
111→                    return; // Block usage on wrong tile
112→                }
113→            }
114→
115→            const handled = game.handlePowerUpAction(row, col, element);
116→            if (handled !== false) {
117→                // If power-up was used successfully, advance tutorial
118→                if (isTutorialActive(game) && isTutorialPowerUpStep(game)) {
119→                    advanceTutorialStep(game);
120→                }
121→                return;
122→            }
123→            // If handlePowerUpAction returns false (swap case), continue with normal drag
124→        }
125→        // Normal drag behavior (including joker)
126→        game.selectedGem = {
127→            element: element,
128→            row: row,
129→            col: col,
130→            tile: tile, // Store tile to detect joker taps later
131→        };
132→        game.isDragging = true;
133→        game.dragStartPos = { x, y };
134→        element.classList.add("dragging");
135→    }
136→}
137→
138→function updateDrag(game, x, y) {
139→    if (!game.isDragging || !game.selectedGem) return;
140→
141→    const element = document.elementFromPoint(x, y);
142→    if (element && element.classList.contains("gem")) {
143→        // If user drags back to the original tile, cancel the preview
144→        if (element === game.selectedGem.element) {
145→            clearDragPreviews();
146→            return;
147→        }
148→
149→        const targetRow = parseInt(element.dataset.row);
150→        const targetCol = parseInt(element.dataset.col);
151→
152→        // Check if gems are adjacent or allowed by extended free swap rules
153→        if (canPreviewSwap(game, game.selectedGem.row, game.selectedGem.col, targetRow, targetCol)) {
154→            previewSwap(game, game.selectedGem.row, game.selectedGem.col, targetRow, targetCol);
155→        }
156→    }
157→}
158→
159→function endDrag(game) {
160→    if (!game.isDragging || !game.selectedGem) return;
161→
162→    const previewGems = document.querySelectorAll(".gem.preview");
163→
164→    if (previewGems.length > 0) {
165→        // User dragged to swap
166→        const targetGem = Array.from(previewGems).find((g) => g !== game.selectedGem.element);
167→        if (targetGem) {
168→            const targetRow = parseInt(targetGem.dataset.row);
169→            const targetCol = parseInt(targetGem.dataset.col);
170→            trySwap(game, game.selectedGem.row, game.selectedGem.col, targetRow, targetCol);
171→        }
172→    } else if (isJoker(game.selectedGem.tile) && !game.activePowerUp) {
173→        // User tapped on joker without dragging - try to activate it
174→        // Only activate if not in power-up mode
175→
176→        // Check if this is a valid tutorial tap
177→        if (isTutorialActive(game) && isTutorialTapStep(game)) {
178→            if (isValidTutorialTap(game, game.selectedGem.row, game.selectedGem.col)) {
179→                activateJokerByTap(game, game.selectedGem.row, game.selectedGem.col, game.selectedGem.element);
180→                // Note: Tutorial progression is handled in the joker activation callback
181→            }
182→        } else if (!isTutorialActive(game)) {
183→            activateJokerByTap(game, game.selectedGem.row, game.selectedGem.col, game.selectedGem.element);
184→        }
185→    } else if (isTileHammerTile(game.selectedGem.tile) && !game.activePowerUp) {
186→        // User tapped on hammer tile without dragging - activate it
187→        // Only activate if not in power-up mode
188→        activateHammerTileByTap(game, game.selectedGem.row, game.selectedGem.col, game.selectedGem.element);
189→    } else if (isTileHalverTile(game.selectedGem.tile) && !game.activePowerUp) {
190→        // User tapped on halver tile without dragging - activate it
191→        // Only activate if not in power-up mode
192→        activateHalverTileByTap(game, game.selectedGem.row, game.selectedGem.col, game.selectedGem.element);
193→    }
194→
195→    // Clean up
196→    document.querySelectorAll(".gem").forEach((gem) => {
197→        gem.classList.remove("dragging", "preview", "merge-preview", "unblock-preview");
198→    });
199→
200→    // Reset hint timer after user interaction completes
201→    game.resetHintTimer();
202→
203→    game.selectedGem = null;
204→    game.isDragging = false;
205→    game.dragStartPos = null;
206→}
207→
208→function activateJokerByTap(game, row, col, element) {
209→    // Activate joker when tapped
210→    const bestValue = findBestJokerValue(game, row, col);
211→
212→    if (bestValue !== null) {
213→        // Transform and animate
214→        game.animating = true;
215→        element.style.transform = "scale(1.2)";
216→        element.textContent = getDisplayValue(bestValue);
217→        element.className = `gem tile-${bestValue}`;
218→
219→        setTimeout(() => {
220→            element.style.transform = "scale(1)";
221→            game.board[row][col] = createTile(bestValue); // Update board
222→
223→            // Set lastSwapPosition to the joker position so other jokers connected to this one can activate
224→            game.lastSwapPosition = { row, col, movedFrom: { row, col } };
225→
226→            game.renderBoard(); // Re-render to show the updated tile
227→
228→            // Progress tutorial if this was a tap-only tutorial step
229→            if (isTutorialActive(game) && isTutorialTapStep(game)) {
230→                advanceTutorialStep(game);
231→            }
232→
233→            setTimeout(() => {
234→                game.isUserSwap = true; // Treat tap as user action
235→                game.processMatches();
236→            }, 200);
237→        }, 300);
238→    } else {
239→        // No valid match found - indicate to user with a shake animation
240→        element.style.animation = "shake 0.3s";
241→        setTimeout(() => {
242→            element.style.animation = "";
243→        }, 300);
244→    }
245→}
246→
247→function activateHammerTileByTap(game, row, col, element) {
248→    // Activate hammer tile when tapped - removes the tile
249→
250→    // Animate removal
251→    game.animating = true;
252→    element.style.transform = "scale(0.5)";
253→    element.style.opacity = "0";
254→
255→    setTimeout(() => {
256→        // Remove the tile from the board
257→        game.board[row][col] = null;
258→        game.renderBoard();
259→
260→        setTimeout(() => {
261→            // Drop tiles and process matches
262→            game.isUserSwap = true;
263→            game.dropGems();
264→        }, 200);
265→    }, 300);
266→}
267→
268→function activateHalverTileByTap(game, row, col, element) {
269→    // Activate halver tile when tapped - halves the tile's value
270→    const currentValue = getTileValue(game.board[row][col]);
271→
272→    // Can only halve if value is greater than 1
273→    if (currentValue <= 1) {
274→        // Cannot halve further - show shake animation
275→        element.style.animation = "shake 0.3s";
276→        setTimeout(() => {
277→            element.style.animation = "";
278→        }, 300);
279→        return;
280→    }
281→
282→    // Calculate new value (halve it)
283→    const newValue = currentValue - 1; // Internal value decreased by 1 (which halves the display value)
284→
285→    // Animate the change
286→    game.animating = true;
287→    element.style.transform = "scale(1.2)";
288→
289→    setTimeout(() => {
290→        element.style.transform = "scale(1)";
291→        // Update the tile to regular tile with new value (no longer a halver tile)
292→        game.board[row][col] = createTile(newValue);
293→        game.renderBoard();
294→
295→        setTimeout(() => {
296→            // Process any matches that may have been created
297→            game.isUserSwap = true;
298→            game.processMatches();
299→        }, 200);
300→    }, 300);
301→}
302→
303→function areAdjacent(row1, col1, row2, col2) {
304→    const rowDiff = Math.abs(row1 - row2);
305→    const colDiff = Math.abs(col1 - col2);
306→    return (rowDiff === 1 && colDiff === 0) || (rowDiff === 0 && colDiff === 1);
307→}
308→
309→function clearDragPreviews() {
310→    document.querySelectorAll(".gem.preview").forEach((gem) => {
311→        gem.classList.remove("preview");
312→    });
313→    document.querySelectorAll(".gem.merge-preview").forEach((gem) => {
314→        gem.classList.remove("merge-preview");
315→    });
316→    document.querySelectorAll(".gem.unblock-preview").forEach((gem) => {
317→        gem.classList.remove("unblock-preview");
318→    });
319→}
320→
321→function canPreviewSwap(game, row1, col1, row2, col2) {
322→    if (areAdjacent(row1, col1, row2, col2)) {
323→        return true;
324→    }
325→
326→    if (game.activePowerUp === "swap" || game.activePowerUp === "teleport") {
327→        return true;
328→    }
329→
330→    if (isTeleportSwapAllowed(game, row1, col1, row2, col2)) {
331→        return true;
332→    }
333→
334→    return isExtendedFreeSwapAllowed(game, row1, col1, row2, col2);
335→}
336→
337→function isTeleportSwapAllowed(game, row1, col1, row2, col2) {
338→    const tile1 = game.board[row1][col1];
339→    const tile2 = game.board[row2][col2];
340→
341→    // Can't teleport to/from blocked tiles
342→    if (isBlocked(tile1) || isBlocked(tile2) || isBlockedWithLife(tile1) || isBlockedWithLife(tile2)) {
343→        return false;
344→    }
345→
346→    const isTeleport1 = (isTileTeleportTile(tile1) || isWildTeleportTile(tile1)) && !tile1.hasBeenSwapped;
347→
348→    return isTeleport1;
349→}
350→
351→function isExtendedFreeSwapAllowed(game, row1, col1, row2, col2) {
352→    if (game.extendedFreeSwap !== true) {
353→        return false;
354→    }
355→
356→    const isHorizontalSwap = row1 === row2;
357→    const isVerticalSwap = col1 === col2;
358→
359→    if (!isHorizontalSwap && !isVerticalSwap) {
360→        return false;
361→    }
362→
363→    const tile1 = game.board[row1][col1];
364→    const tile2 = game.board[row2][col2];
365→
366→    const isFreeSwap1 = (isTileFreeSwapTile(tile1) || isTileStickyFreeSwapTile(tile1)) && !tile1.hasBeenSwapped;
367→    const isFreeSwap2 = (isTileFreeSwapTile(tile2) || isTileStickyFreeSwapTile(tile2)) && !tile2.hasBeenSwapped;
368→
369→    const isDirectionalFreeSwap1 =
370→        !tile1.hasBeenSwapped &&
371→        ((isTileFreeSwapHorizontalTile(tile1) && isHorizontalSwap) ||
372→            (isTileFreeSwapVerticalTile(tile1) && isVerticalSwap));
373→    const isDirectionalFreeSwap2 =
374→        !tile2.hasBeenSwapped &&
375→        ((isTileFreeSwapHorizontalTile(tile2) && isHorizontalSwap) ||
376→            (isTileFreeSwapVerticalTile(tile2) && isVerticalSwap));
377→
378→    return isFreeSwap1 || isFreeSwap2 || isDirectionalFreeSwap1 || isDirectionalFreeSwap2;
379→}
380→
381→function previewSwap(game, row1, col1, row2, col2) {
382→    // Clear previous previews
383→    clearDragPreviews();
384→
385→    // Add preview to both gems
386→    const gem1 = document.querySelector(`[data-row="${row1}"][data-col="${col1}"]`);
387→    const gem2 = document.querySelector(`[data-row="${row2}"][data-col="${col2}"]`);
388→
389→    if (gem1 && gem2) {
390→        gem1.classList.add("preview");
391→        gem2.classList.add("preview");
392→
393→        // Get tiles that would merge if swap completes
394→        const matchTiles = getMatchTilesForSwap(game, row1, col1, row2, col2);
395→
396→        // Highlight merge tiles
397→        for (const tile of matchTiles) {
398→            const matchGem = document.querySelector(`[data-row="${tile.row}"][data-col="${tile.col}"]`);
399→            matchGem?.classList.add("merge-preview");
400→        }
401→
402→        // Highlight blocked tiles that would be unblocked
403→        // matchTiles are in PRE-SWAP coords, convert to POST-SWAP for adjacency check
404→        const blockedToUnblock = getBlockedTilesForMatch(game, matchTiles, row1, col1, row2, col2);
405→        for (const pos of blockedToUnblock) {
406→            const blockedGem = document.querySelector(`[data-row="${pos.row}"][data-col="${pos.col}"]`);
407→            blockedGem?.classList.add("unblock-preview");
408→        }
409→    }
410→}
411→
412→function getBlockedTilesForMatch(game, matchTiles, row1, col1, row2, col2) {
413→    const blockedSet = new Set();
414→    const result = [];
415→
416→    for (const tile of matchTiles) {
417→        // Convert pre-swap to post-swap coordinates
418→        let checkRow = tile.row;
419→        let checkCol = tile.col;
420→        if (tile.row === row1 && tile.col === col1) {
421→            checkRow = row2;
422→            checkCol = col2;
423→        } else if (tile.row === row2 && tile.col === col2) {
424→            checkRow = row1;
425→            checkCol = col1;
426→        }
427→
428→        const adjacentPositions = [
429→            { row: checkRow - 1, col: checkCol },
430→            { row: checkRow + 1, col: checkCol },
431→            { row: checkRow, col: checkCol - 1 },
432→            { row: checkRow, col: checkCol + 1 },
433→        ];
434→
435→        for (const pos of adjacentPositions) {
436→            if (pos.row >= 0 && pos.row < game.boardHeight && pos.col >= 0 && pos.col < game.boardWidth) {
437→                const key = `${pos.row}_${pos.col}`;
438→                if (!blockedSet.has(key)) {
439→                    const adjacentTile = game.board[pos.row][pos.col];
440→                    if (
441→                        isBlocked(adjacentTile) ||
442→                        isBlockedWithLife(adjacentTile) ||
443→                        isBlockedMovable(adjacentTile) ||
444→                        isBlockedWithMergeCount(adjacentTile)
445→                    ) {
446→                        blockedSet.add(key);
447→                        result.push(pos);
448→                    }
449→                }
450→            }
451→        }
452→    }
453→
454→    return result;
455→}
456→
457→/**
458→ * Execute the board-level swap logic (pure: no DOM, no animation).
459→ * Mutates game.board and game state flags.
460→ * @returns {{ valid: boolean, hasMatch: boolean, hasFreeSwap: boolean, hasTeleport: boolean,
461→ *             isSwapPowerUp: boolean, isTeleportPowerUp: boolean, allowNonMatchingSwap: boolean }}
462→ *   An invalid or disallowed swap is indicated by `valid: false`.
463→ */
464→export function executeSwap(game, row1, col1, row2, col2) {
465→    const tile1 = game.board[row1][col1];
466→    const tile2 = game.board[row2][col2];
467→
468→    const isHorizontalSwap = row1 === row2;
469→    const isVerticalSwap = col1 === col2;
470→
471→    const isFreeSwap1 = (isTileFreeSwapTile(tile1) || isTileStickyFreeSwapTile(tile1)) && !tile1.hasBeenSwapped;
472→    const isFreeSwap2 = (isTileFreeSwapTile(tile2) || isTileStickyFreeSwapTile(tile2)) && !tile2.hasBeenSwapped;
473→    const isDirectionalFreeSwap1 =
474→        !tile1.hasBeenSwapped &&
475→        ((isTileFreeSwapHorizontalTile(tile1) && isHorizontalSwap) ||
476→            (isTileFreeSwapVerticalTile(tile1) && isVerticalSwap));
477→    const isDirectionalFreeSwap2 =
478→        !tile2.hasBeenSwapped &&
479→        ((isTileFreeSwapHorizontalTile(tile2) && isHorizontalSwap) ||
480→            (isTileFreeSwapVerticalTile(tile2) && isVerticalSwap));
481→    const hasFreeSwap = isFreeSwap1 || isFreeSwap2 || isDirectionalFreeSwap1 || isDirectionalFreeSwap2;
482→    const hasTeleport = (isTileTeleportTile(tile1) || isWildTeleportTile(tile1)) && !tile1.hasBeenSwapped;
483→    const isSwapPowerUp = game.activePowerUp === "swap";
484→    const isTeleportPowerUp = game.activePowerUp === "teleport";
485→    const allowNonMatchingSwap = game.allowNonMatchingSwaps === true;
486→
487→    // Perform the board swap
488→    const temp = game.board[row1][col1];
489→    game.board[row1][col1] = game.board[row2][col2];
490→    game.board[row2][col2] = temp;
491→
492→    game.lastSwapPosition = { row: row2, col: col2, movedFrom: { row: row1, col: col1 } };
493→    game.isUserSwap = true;
494→
495→    const hasMatch = game.hasMatchesForSwap(row1, col1, row2, col2);
496→
497→    if (hasMatch || isSwapPowerUp || isTeleportPowerUp || hasFreeSwap || hasTeleport || allowNonMatchingSwap) {
498→        // Count the move
499→        if (!isSwapPowerUp && !isTeleportPowerUp && !hasFreeSwap && !hasTeleport) {
500→            game.movesUsed++;
501→        }
502→
503→        game.shouldDecrementCursedTimers = true;
504→        game.cursedTileCreatedThisTurn = {};
505→
506→        // Mark free swap tiles as used (tiles have been swapped, so tile1 is now at row2/col2)
507→        if (hasFreeSwap) {
508→            if (isFreeSwap1 || isDirectionalFreeSwap1) game.board[row2][col2].hasBeenSwapped = true;
509→            if (isFreeSwap2 || isDirectionalFreeSwap2) game.board[row1][col1].hasBeenSwapped = true;
510→        }
511→        if (hasTeleport) {
512→            game.board[row2][col2].hasBeenSwapped = true;
513→        }
514→
515→        return { valid: true, hasMatch, hasFreeSwap, hasTeleport, isSwapPowerUp, isTeleportPowerUp, allowNonMatchingSwap };
516→    } else {
517→        // Revert the swap
518→        game.board[row2][col2] = game.board[row1][col1];
519→        game.board[row1][col1] = temp;
520→        game.lastSwapPosition = null;
521→        game.isUserSwap = false;
522→        return { valid: false, hasMatch: false, hasFreeSwap, hasTeleport, isSwapPowerUp, isTeleportPowerUp, allowNonMatchingSwap };
523→    }
524→}
525→
526→export function trySwap(game, row1, col1, row2, col2) {
527→    if (!game.gameActive) return;
528→
529→    // Tutorial validation - only allow defined swaps during tutorial
530→    if (isTutorialActive(game)) {
531→        if (!isValidTutorialSwap(game, row1, col1, row2, col2)) {
532→            game.animateRevert(row1, col1, row2, col2);
533→            return false;
534→        }
535→    }
536→
537→    // Prevent swapping if either tile is blocked or blocked with life
538→    // BLOCKED_MOVABLE tiles CAN be swapped
539→    if (
540→        isBlocked(game.board[row1][col1]) ||
541→        isBlocked(game.board[row2][col2]) ||
542→        isBlockedWithLife(game.board[row1][col1]) ||
543→        isBlockedWithLife(game.board[row2][col2])
544→    ) {
545→        return;
546→    }
547→
548→    const isAdjacentSwap = areAdjacent(row1, col1, row2, col2);
549→    const allowExtendedFreeSwap = !isAdjacentSwap && isExtendedFreeSwapAllowed(game, row1, col1, row2, col2);
550→    const allowTeleportSwap = !isAdjacentSwap && isTeleportSwapAllowed(game, row1, col1, row2, col2);
551→    const isPowerUpSwap = !isAdjacentSwap && (game.activePowerUp === "swap" || game.activePowerUp === "teleport");
552→
553→    if (!isAdjacentSwap && !allowExtendedFreeSwap && !allowTeleportSwap && !isPowerUpSwap) {
554→        return false;
555→    }
556→
557→    // If animating, queue the swap to execute after animation completes
558→    if (game.animating) {
559→        game.interruptCascade = true;
560→        game.pendingSwap = {
561→            row1,
562→            col1,
563→            row2,
564→            col2,
565→            tile1: game.board[row1][col1],
566→            tile2: game.board[row2][col2],
567→        };
568→
569→        const gem1 = document.querySelector(`[data-row="${row1}"][data-col="${col1}"]`);
570→        const gem2 = document.querySelector(`[data-row="${row2}"][data-col="${col2}"]`);
571→        if (gem1) gem1.classList.add("pending-preview");
572→        if (gem2) gem2.classList.add("pending-preview");
573→
574→        return;
575→    }
576→
577→    // Execute board-level swap logic
