}

.goal-icon {
    position: absolute;
    top: -12px;
    left: 50%;
    transform: translateX(-50%);
    background: #141414;
    border-radius: 35%;
    font-size: 1rem;
    line-height: 1rem;
    width: 1.2rem;
    height: 1.2rem;
    text-align: center;
