    font-weight: 900;
    position: absolute;
    bottom: -6px;
    left: 50%;
    transform: translateX(-50%);
}

.goal-progress stroked-text {
    height: 1.2rem;
}

.goal-check {
    position: absolute;
    bottom: -2px;
    left: 50%;
    transform: translateX(-50%);
    background: #5aec69;
    border: 3px solid black;
    color: black;
    width: 24px;
    height: 24px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-family:
        system-ui,
        -apple-system,
        BlinkMacSystemFont,
        "Segoe UI",
        Roboto,
        Oxygen,
        Ubuntu,
        Cantarell,
        "Open Sans",
        "Helvetica Neue",
