.gem.tile-BLOCKED {
    background: var(--tile-blocked-bg);
    color: transparent;
    border: 2px solid var(--tile-blocked-border);
    position: relative;
    overflow: hidden;
}

.gem.tile-BLOCKED::before {
    content: "";
    position: absolute;
    top: 45%;
    left: 50%;
    width: 60%;
    height: 60%;
    background:
        linear-gradient(
            45deg,
            transparent 30%,
            var(--tile-blocked-x-color) 30%,
            var(--tile-blocked-x-color) 70%,
            transparent 70%
        ),
        linear-gradient(
            -45deg,
            transparent 30%,
            var(--tile-blocked-x-color) 30%,
            var(--tile-blocked-x-color) 70%,
            transparent 70%
        );
    transform: translate(-50%, -50%);
}

.gem.tile-BLOCKED.unblocking {
    animation: unblock-move 0.6s ease-out forwards;
    z-index: 200;
}

.gem.tile-BLOCKED_WITH_LIFE {
    background: var(--tile-blocked-bg);
    color: var(--tile-blocked-life-color);
    border: 2px solid var(--tile-blocked-border);
    font-size: clamp(1.2rem, 4vw, 1.8rem);
    font-weight: bold;
    display: flex;
    align-items: center;
    justify-content: center;
    position: relative;
    overflow: visible;
}

.gem.tile-BLOCKED_WITH_LIFE::before {
    content: "";
    position: absolute;
    top: 50%;
    left: 50%;
    width: 60%;
    height: 60%;
    background:
        linear-gradient(
            45deg,
            transparent 30%,
            var(--tile-blocked-x-color) 30%,
            var(--tile-blocked-x-color) 70%,
            transparent 70%
        ),
        linear-gradient(
            -45deg,
            transparent 30%,
            var(--tile-blocked-x-color) 30%,
            var(--tile-blocked-x-color) 70%,
            transparent 70%
        );
    transform: translate(-50%, -50%);
    z-index: 0;
}

.gem.tile-BLOCKED_WITH_LIFE::after {
    content: attr(data-life);
    position: relative;
    z-index: 1;
    color: var(--tile-blocked-life-color);
    font-size: clamp(1rem, 40cqw, 1.2rem);
    font-weight: bold;
}

/* Blocked tile damage shake */
@keyframes blockedShake {
    0%,
    100% {
        transform: translateX(0);
    }
    15% {
        transform: translateX(calc(-1 * var(--shake-intensity)));
    }
    30% {
        transform: translateX(var(--shake-intensity));
    }
    45% {
        transform: translateX(calc(-0.7 * var(--shake-intensity)));
    }
    60% {
        transform: translateX(calc(0.5 * var(--shake-intensity)));
    }
    75% {
        transform: translateX(calc(-0.3 * var(--shake-intensity)));
    }
}

.gem.blocked-damaged {
    animation: blockedShake 0.35s ease-out;
}

/* Floating damage text */
@keyframes damageFloat {
    0% {
        opacity: 1;
        transform: translateX(-10%) translateY(0) scale(1);
    }
    20% {
        opacity: 1;
        transform: translateX(-10%) translateY(-10px) scale(1.1);
    }
    100% {
        opacity: 0;
        transform: translateX(-10%) translateY(-50px) scale(0.8);
    }
}

.damage-text {
    position: fixed;
    z-index: 1000;
    pointer-events: none;
    font-weight: bolder;
    font-style: italic;
    font-size: clamp(0.6rem, 30cqw, 1.2rem);
    color: #ff4444;
    text-shadow:
        0 0 3px rgba(0, 0, 0, 0.8),
        0 1px 2px rgba(0, 0, 0, 0.6);
    animation: damageFloat 0.8s ease-out forwards;
}

.gem.tile-BLOCKED_WITH_LIFE.unblocking {
    animation: shakeShrink 0.6s ease-out forwards;
    z-index: 200;
}

@keyframes shakeShrink {
    0% {
        transform: translateX(0) scale(1);
        opacity: 1;
    }
    10% {
        transform: translateX(calc(-1 * var(--shake-intensity, 8px))) scale(1.05);
    }
    20% {
        transform: translateX(calc(var(--shake-intensity, 8px))) scale(1.05);
    }
    25% {
        transform: translateX(calc(-0.7 * var(--shake-intensity, 8px))) scale(1.05);
    }
    30% {
        transform: translateX(calc(0.5 * var(--shake-intensity, 8px))) scale(1.05);
    }
    35% {
        transform: translateX(calc(-0.3 * var(--shake-intensity, 8px))) scale(1.05);
    }
    40% {
        transform: translateX(0) scale(0.95);
    }
    45% {
        transform: translateX(0) scale(0.9);
    }
    55% {
        transform: translateX(0) scale(0.7);
        opacity: 0.8;
    }
    100% {
        transform: translateX(0) scale(0);
        opacity: 0;
    }
}

.gem.shake-shrink {
    animation: shakeShrink 0.6s ease-out forwards;
    z-index: 200;
}

.gem.tile-BLOCKED_MOVABLE {
    background: var(--tile-blocked-movable-bg);
    color: transparent;
    border: 2px solid var(--tile-blocked-movable-border);
    position: relative;
    overflow: visible;
    cursor: pointer;
}

.gem.tile-BLOCKED_MOVABLE::before {
    content: "";
    position: absolute;
    top: 45%;
    left: 50%;
    width: 60%;
    height: 60%;
    background:
        linear-gradient(
            45deg,
            transparent 30%,
            var(--tile-blocked-x-color) 30%,
            var(--tile-blocked-x-color) 70%,
            transparent 70%
        ),
        linear-gradient(
            -45deg,
            transparent 30%,
            var(--tile-blocked-x-color) 30%,
            var(--tile-blocked-x-color) 70%,
            transparent 70%
        );
    transform: translate(-50%, -50%);
}

.gem.tile-BLOCKED_MOVABLE::after {
    content: "";
    width: 60%;
    height: 60%;
    position: absolute;
    top: 44%;
    left: 50%;
    transform: translate(-50%, -50%);
    background-image: url("../assets/arrow-all-directions.svg");
    background-size: 60%;
    background-position: center;
    background-repeat: no-repeat;
    z-index: 1;
    opacity: 0.7;
}

/* Blocked tiles with merge count (per-cell tracking) */
.gem.tile-BLOCKED.tile-BLOCKED-merge-count {
    background: var(--tile-blocked-bg);
    border: 2px solid var(--tile-blocked-border);

    /* CSS Grid for positioning X markers */
    display: grid;
    grid-template-columns: repeat(var(--rect-width), 1fr);
    grid-template-rows: repeat(var(--rect-height), 1fr);
    gap: clamp(1px, 0.7vw, 3px); /* Match board gap */

    &::before {
        display: none;
    }
}

/* Individual X marker cells */
.cell-x-marker {
    position: relative;
    display: flex;
    align-items: center;
    justify-content: center;
    width: 100%;
    height: 100%;
}

/* X pattern for each cell */
.cell-x-marker::before {
    content: "";
    position: absolute;
    width: 60%;
    height: 60%;
    background:
        linear-gradient(
            45deg,
            transparent 30%,
            var(--tile-blocked-x-color) 30%,
            var(--tile-blocked-x-color) 70%,
            transparent 70%
        ),
        linear-gradient(
            -45deg,
            transparent 30%,
            var(--tile-blocked-x-color) 30%,
            var(--tile-blocked-x-color) 70%,
            transparent 70%
        );
}

/* X removal animation */
@keyframes cell-x-fadeout {
    0% {
        opacity: 1;
        transform: scale(1);
    }
    50% {
        opacity: 0.5;
        transform: scale(1.2);
    }
    100% {
        opacity: 0;
        transform: scale(0);
    }
}

.cell-x-removing {
    animation: cell-x-fadeout 0.3s ease-out forwards;
}

/* Rectangular blocked tiles */
.gem.rectangular-blocked {
    /* Override aspect-ratio for rectangular shapes */
    aspect-ratio: auto;

    /* Ensure proper sizing within spanned grid cells */
    width: 100%;
    height: 100%;
    border-radius: 20px;

    &.goal-tile {
        width: 30vw;
        height: 30vw;
    }
}

.gem.matched {
    animation: match-animation 0.5s ease-out forwards;
}

.gem.sliding {
    z-index: 20;
    transition:
        transform 0.4s ease-out,
        opacity 0.3s ease-out;
}

.gem.merge-target {
    animation: merge-pulse 0.4s ease-in forwards;
}

/* .gem.falling animation is now handled via inline styles in animator.js */

.gem.new-gem {
    opacity: 0; /* Start invisible until animation begins */
    animation: new-gem-animation 0.4s ease-in forwards;
}

.bottom-container {
    flex: 1 1 0;
    min-height: clamp(100px, 20vw, 150px);
    position: relative;
}

.controls {
    display: flex;
    gap: clamp(6px, 2vw, 10px);
    justify-content: center;
    flex-shrink: 0;
    align-items: center;
    position: absolute;
    bottom: 6vh;
    left: 0;
